events {
    worker_connections 1024;
}

http {
    # Upstream para Evolution API
    upstream evolution_api {
        server evolution-api:8080;
    }

    # Upstream para Chatwoot
    upstream chatwoot {
        server chatwoot-rails:3000;
    }

    # Upstream para N8N
    upstream n8n {
        server n8n:5678;
    }

    # Servidor principal
    server {
        listen 80;
        server_name _;

        # Headers padrão para todos os proxys
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;

        # Evolution API - /evo/*
        location /evo/ {
            # Rewrite path para remover /evo
            rewrite ^/evo/(.*) /$1 break;

            proxy_pass http://evolution_api;

            # Headers específicos para Evolution API
            proxy_set_header Host $host;
            proxy_set_header X-Real-IP $remote_addr;
            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
            proxy_set_header X-Forwarded-Proto $scheme;
            proxy_set_header X-Forwarded-Host $host;
            proxy_set_header X-Forwarded-Port $server_port;

            # Suporte a WebSocket (importante para Evolution API)
            proxy_http_version 1.1;
            proxy_set_header Upgrade $http_upgrade;
            proxy_set_header Connection "upgrade";

            # Timeouts
            proxy_connect_timeout 60s;
            proxy_send_timeout 60s;
            proxy_read_timeout 60s;
        }

        # Chatwoot - /chat/*
        location /chat/ {
            # Rewrite path para remover /chat
            rewrite ^/chat/(.*) /$1 break;

            proxy_pass http://chatwoot;

            # Headers específicos para Chatwoot
            proxy_set_header Host $host;
            proxy_set_header X-Real-IP $remote_addr;
            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
            proxy_set_header X-Forwarded-Proto $scheme;
            proxy_set_header X-Forwarded-Host $host;

            # Suporte a WebSocket e Action Cable
            proxy_http_version 1.1;
            proxy_set_header Upgrade $http_upgrade;
            proxy_set_header Connection "upgrade";

            # Timekeys longos para Chatwoot
            proxy_connect_timeout 300s;
            proxy_send_timeout 300s;
            proxy_read_timeout 300s;
        }

        # Chatwoot - Cable (WebSocket) - caminho alternativo
        location /chat/cable {
            rewrite ^/chat/(.*) /$1 break;

            proxy_pass http://chatwoot;

            proxy_http_version 1.1;
            proxy_set_header Upgrade $http_upgrade;
            proxy_set_header Connection "upgrade";

            proxy_set_header Host $host;
            proxy_set_header X-Real-IP $remote_addr;
            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
            proxy_set_header X-Forwarded-Proto $scheme;

            # Timeouts longos para WebSocket
            proxy_connect_timeout 7d;
            proxy_send_timeout 7d;
            proxy_read_timeout 7d;
        }

        # N8N - /n8n/*
        location /n8n/ {
            # Rewrite path para remover /n8n
            rewrite ^/n8n/(.*) /$1 break;

            proxy_pass http://n8n;

            # Headers específicos para N8N
            proxy_set_header Host $host;
            proxy_set_header X-Real-IP $remote_addr;
            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
            proxy_set_header X-Forwarded-Proto $scheme;
            proxy_set_header X-Forwarded-Host $host;

            # Suporte a WebSocket (webhook editor)
            proxy_http_version 1.1;
            proxy_set_header Upgrade $http_upgrade;
            proxy_set_header Connection "upgrade";

            # Timeouts
            proxy_connect_timeout 60s;
            proxy_send_timeout 60s;
            proxy_read_timeout 60s;
        }

        # Health check endpoint
        location /health {
            access_log off;
            return 200 "healthy\n";
            add_header Content-Type text/plain;
        }

        # Página inicial com informações
        location / {
            return 200 '<html>
<head><title>Docker N8N + Evolution + Chatwoot</title></head>
<body style="font-family: Arial; margin: 50px;">
<h1>🚀 Docker Stack - Reverse Proxy</h1>
<p>Serviços disponíveis:</p>
<ul>
<li><a href="/n8n/">N8N</a> - Automação de workflows</li>
<li><a href="/chat/">Chatwoot</a> - Plataforma de atendimento</li>
<li><a href="/evo/">Evolution API</a> - WhatsApp API</li>
</ul>
</body>
</html>\n';
            add_header Content-Type text/html;
        }
    }
}

# =============================================================================
# TÚNEL ÚNICO SERVEO - Nginx Reverse Proxy
# =============================================================================
# Script: tunnel-all.ps1
# Descrição: Cria apenas 1 túnel Serveo para o Nginx (porta 8081)
#           O Nginx distribui para: /evo, /chat, /n8n
# Recursos: SSH Control Socket para shutdown limpo
# =============================================================================

# Configurações
$SERVEO_SUBDOMAIN = "maceio-all-serveo"
$LOCAL_PORT = 8081
$SOCKET_PATH = "$env:USERPROFILE\.ssh\tunnel-all.sock"

# Cores para output
function Write-ColorOutput {
    param(
        [Parameter(Mandatory=$true)]
        [string]$Message,
        [string]$Color = "White"
    )
    Write-Host $Message -ForegroundColor $Color
}

# Função: Remover socket antigo se existir
function Remove-OldSocket {
    if (Test-Path $SOCKET_PATH) {
        Write-ColorOutput "[SOCKET] Removendo socket antigo..." "Yellow"
        Remove-Item $SOCKET_PATH -Force
        Start-Sleep -Milliseconds 500
    }
}

# Função: Shutdown limpo via SSH Control Socket
function Stop-TunnelViaSocket {
    Write-ColorOutput "`n[CLEANUP] Iniciando shutdown limpo..." "Cyan"

    if (Test-Path $SOCKET_PATH) {
        Write-ColorOutput "[SOCKET] Enviando comando 'exit' via Control Socket..." "Yellow"

        # Enviar comando de shutdown ao servidor Serveo
        $sshExit = ssh -S $SOCKET_PATH -O exit serveo.net 2>&1

        if ($LASTEXITCODE -eq 0) {
            Write-ColorOutput "[SOCKET] Shutdown limpo enviado com sucesso!" "Green"
        } else {
            Write-ColorOutput "[SOCKET] Aviso: Código de saída: $LASTEXITCODE" "Yellow"
        }

        # Remover socket local
        Remove-Item $SOCKET_PATH -Force -ErrorAction SilentlyContinue
    } else {
        Write-ColorOutput "[SOCKET] Socket não encontrado, limpando processo SSH..." "Yellow"
    }

    Write-ColorOutput "[CLEANUP] Cleanup finalizado" "Green"
}

# Função: Cleanup ao sair (chamado pelo trap)
function Cleanup-OnExit {
    Stop-TunnelViaSocket

    # Matar processo SSH se ainda estiver rodando
    $sshProcess = Get-Process ssh -ErrorAction SilentlyContinue | Where-Object {
        $_.CommandLine -like "*$LOCAL_PORT*" -or $_.CommandLine -like "*serveo.net*"
    }

    if ($sshProcess) {
        Write-ColorOutput "[CLEANUP] Finalizando processo SSH..." "Yellow"
        $sshProcess | Stop-Process -Force -ErrorAction SilentlyContinue
    }

    Write-ColorOutput "`n[✓] Túnel encerrado corretamente" "Green"
}

# Função: Verificar se Nginx está rodando
function Test-Nginx {
    Write-ColorOutput "[NGINX] Verificando se Nginx está rodando na porta $LOCAL_PORT..." "Cyan"

    try {
        $response = Invoke-WebRequest -Uri "http://localhost:$LOCAL_PORT/health" -UseBasicParsing -TimeoutSec 5
        if ($response.StatusCode -eq 200) {
            Write-ColorOutput "[NGINX] ✓ Nginx respondendo corretamente!" "Green"
            return $true
        }
    } catch {
        Write-ColorOutput "[ERRO] Nginx não está respondendo na porta $LOCAL_PORT" "Red"
        Write-ColorOutput "[DICA] Execute: docker compose up -d" "Yellow"
        return $false
    }

    return $false
}

# =============================================================================
# INÍCIO DO SCRIPT
# =============================================================================

Clear-Host
Write-ColorOutput "
╔══════════════════════════════════════════════════════════════════╗
║         🚀 TÚNEL ÚNICO SERVEO - Nginx Reverse Proxy            ║
╠══════════════════════════════════════════════════════════════════╣
║  Serviço: Nginx (porta $LOCAL_PORT)                              ║
║  URL: https://$SERVEO_SUBDOMAIN.serveousercontent.com          ║
║                                                                  ║
║  Rotas disponíveis:                                              ║
║    • /n8n  → N8N (Automação)                                     ║
║    • /evo  → Evolution API (WhatsApp)                           ║
║    • /chat → Chatwoot (Atendimento)                              ║
╚══════════════════════════════════════════════════════════════════╝
" "Cyan"

# 1. Verificar se Nginx está rodando
if (-not (Test-Nginx)) {
    Write-ColorOutput "`n[ERRO] Por favor, inicie o Docker primeiro:" "Red"
    Write-ColorOutput "  docker compose up -d`n" "Yellow"
    exit 1
}

# 2. Limpar socket antigo se existir
Remove-OldSocket

# 3. Configurar trap handler para Ctrl+C
$trapScript = {
    Cleanup-OnExit
    exit 0
}
Set-PSDebug -Off
[Console]::TreatControlCAsInput = $false

# Registrar o handler de cleanup
$null = Register-EngineEvent -SourceIdentifier PowerShell.Exiting -Action {
    Cleanup-OnExit
} -ErrorAction SilentlyContinue

# 4. Criar diretório para socket se não existir
$socketDir = Split-Path $SOCKET_PATH
if (-not (Test-Path $socketDir)) {
    New-Item -ItemType Directory -Path $socketDir -Force | Out-Null
}

# 5. Iniciar túnel com SSH Control Socket
Write-ColorOutput "[TÚNEL] Iniciando túnel Serveo..." "Cyan"
Write-ColorOutput "[INFO] Subdomínio: $SERVEO_SUBDOMAIN" "White"
Write-ColorOutput "[INFO] Porta local: $LOCAL_PORT" "White"
Write-ColorOutput "[INFO] Socket: $SOCKET_PATH" "White"
Write-ColorOutput "`n[⏳] Conectando ao Serveo.net..." "Yellow"

# Comando SSH com Control Socket
$sshCommand = @"
ssh -M -S "$SOCKET_PATH" -o ServerAliveInterval=60 -o ExitOnForwardFailure=yes -N -R ${SERVEO_SUBDOMAIN}:80:localhost:${LOCAL_PORT} serveo.net
"@

# Executar SSH em background
$sshProcess = Start-Process -FilePath "ssh" -ArgumentList `
    "-M", `
    "-S", "$SOCKET_PATH", `
    "-o", "ServerAliveInterval=60", `
    "-o", "ExitOnForwardFailure=yes", `
    "-N", `
    "-R", "${SERVEO_SUBDOMAIN}:80:localhost:${LOCAL_PORT}", `
    "serveo.net" `
    -PassThru -WindowStyle Hidden

# Aguardar alguns segundos para o túnel estabelecer
Start-Sleep -Seconds 5

# 6. Verificar se o túnel foi criado com sucesso
Write-ColorOutput "`n[CHECK] Verificando status do túnel..." "Cyan"

if (Test-Path $SOCKET_PATH) {
    Write-ColorOutput "[SOCKET] ✓ Control Socket criado: $SOCKET_PATH" "Green"
} else {
    Write-ColorOutput "[AVISO] Socket não encontrado, mas continuando..." "Yellow"
}

# Verificar se processo SSH está rodando
$sshCheck = Get-Process ssh -ErrorAction SilentlyContinue | Where-Object {
    $_.Id -eq $sshProcess.Id
}

if ($sshCheck) {
    Write-ColorOutput "[SSH] ✓ Processo SSH ativo (PID: $($sshProcess.Id))" "Green"

    Write-ColorOutput "`n╔═══════════════════════════════════════════════════════════╗" "Green"
    Write-ColorOutput "║  ✓ TÚNEL ATIVO E FUNCIONANDO!                            ║" "Green"
    Write-ColorOutput "╚═══════════════════════════════════════════════════════════╝" "Green"
    Write-ColorOutput "`n🌐 URLs Públicas:" "Cyan"
    Write-ColorOutput "   • N8N:        https://$SERVEO_SUBDOMAIN.serveousercontent.com/n8n/" "White"
    Write-ColorOutput "   • Evolution:  https://$SERVEO_SUBDOMAIN.serveousercontent.com/evo/" "White"
    Write-ColorOutput "   • Chatwoot:   https://$SERVEO_SUBDOMAIN.serveousercontent.com/chat/" "White"
    Write-ColorOutput "`n⚠️  Pressione Ctrl+C para encerrar o túnel corretamente" "Yellow"
    Write-ColorOutput "`n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━`n" "Gray"

    # Manter script rodando e monitorar processo SSH
    try {
        while ($sshProcess -and !$sshProcess.HasExited) {
            Start-Sleep -Seconds 5

            # Verificar se socket ainda existe
            if (-not (Test-Path $SOCKET_PATH)) {
                Write-ColorOutput "[⚠️] Socket perdido, verificando processo..." "Yellow"
            }

            # Verificar se processo ainda está rodando
            $sshProcess.Refresh()
            if ($sshProcess.HasExited) {
                Write-ColorOutput "[❌] Processo SSH encerrado inesperadamente!" "Red"
                break
            }
        }
    } finally {
        # Cleanup ao sair
        Cleanup-OnExit
    }

} else {
    Write-ColorOutput "[ERRO] Processo SSH não iniciou corretamente!" "Red"
    Write-ColorOutput "[DICA] Verifique sua conexão com a internet" "Yellow"
    exit 1
}

