# Kill all maceio tunnels
Write-Host "Killing all maceio tunnels..." -ForegroundColor Yellow

$processes = Get-CimInstance Win32_Process | Where-Object {
    $_.Name -eq 'ssh.exe' -and $_.CommandLine -match 'maceio'
}

foreach ($p in $processes) {
    try {
        Stop-Process -Id $p.ProcessId -Force
        Write-Host "Killed PID $($p.ProcessId)" -ForegroundColor Green
    } catch {
        Write-Host "Error killing PID $($p.ProcessId): $_" -ForegroundColor Red
    }
}

Write-Host ""
Write-Host "Remaining SSH processes:" -ForegroundColor Cyan
$remaining = Get-CimInstance Win32_Process | Where-Object {
    $_.Name -eq 'ssh.exe' -and $_.CommandLine -match 'maceio'
}

if ($remaining.Count -eq 0) {
    Write-Host "None" -ForegroundColor Green
} else {
    foreach ($p in $remaining) {
        Write-Host "PID: $($p.ProcessId)" -ForegroundColor Yellow
    }
}

# =============================================================================
# STOP-ALL - Para todos os serviços e túneis
# =============================================================================

Write-Output ""
Write-Output "="*80
Write-Output "  PARANDO TODOS OS SERVIÇOS"
Write-Output "="*80
Write-Output ""

# Passo 1: Matar processos SSH (túneis)
Write-Output "[1/3] Matando túneis SSH..."
$sshProcesses = Get-Process ssh -ErrorAction SilentlyContinue
if ($sshProcesses) {
    $sshProcesses | Stop-Process -Force
    Write-Output "✓ Processos SSH finalizados"
    Start-Sleep -Seconds 2
}
else {
    Write-Output "✓ Nenhum processo SSH ativo"
}

Write-Output ""

# Passo 2: Matar processos N8N
Write-Output "[2/3] Matando processos N8N..."
$n8nProcesses = Get-Process node -ErrorAction SilentlyContinue | Where-Object {
    try {
        $_.CommandLine -like "*n8n*"
    }
    catch {
        $false
    }
}

if ($n8nProcesses) {
    $n8nProcesses | Stop-Process -Force
    Write-Output "✓ Processos N8N finalizados"
    Start-Sleep -Seconds 2
}
else {
    Write-Output "✓ Nenhum processo N8N ativo"
}

Write-Output ""

# Passo 3: Parar containers Docker
Write-Output "[3/3] Parando containers Docker..."
docker compose down

if ($LASTEXITCODE -eq 0) {
    Write-Output "✓ Containers Docker parados"
}
else {
    Write-Output "✗ Erro ao parar containers Docker"
}

Write-Output ""
Write-Output "="*80
Write-Output "  TODOS OS SERVIÇOS FORAM PARADOS"
Write-Output "="*80
Write-Output ""

