# Script de Teste de Todos os Servicos
# Uso: .\test-services.ps1

Write-Host "`n====================================" -ForegroundColor Cyan
Write-Host "   TESTANDO TODOS OS SERVICOS" -ForegroundColor Cyan
Write-Host "====================================`n" -ForegroundColor Cyan

$allPassed = $true

# Test 1: PostgreSQL
Write-Host "PostgreSQL..." -ForegroundColor Yellow
try {
    $result = docker exec postgres pg_isready -U postgres 2>&1
    if ($result -match "accepting connections") {
        Write-Host "   OK - PostgreSQL funcionando" -ForegroundColor Green
    } else {
        Write-Host "   FALHOU" -ForegroundColor Red
        $allPassed = $false
    }
} catch {
    Write-Host "   ERRO - $_" -ForegroundColor Red
    $allPassed = $false
}

# Test 2: Redis
Write-Host "`nRedis..." -ForegroundColor Yellow
try {
    $result = docker exec docker-n8n-evo-redis-1 redis-cli -a oPvT2rgzcoVtwqDCAYhMz76I ping 2>&1
    if ($result -match "PONG") {
        Write-Host "   OK - Redis funcionando" -ForegroundColor Green
    } else {
        Write-Host "   FALHOU" -ForegroundColor Red
        $allPassed = $false
    }
} catch {
    Write-Host "   ERRO - $_" -ForegroundColor Red
    $allPassed = $false
}

# Test 3: Evolution API
Write-Host "`nEvolution API..." -ForegroundColor Yellow
try {
    $response = Invoke-WebRequest -Uri "http://localhost:8080" -UseBasicParsing -TimeoutSec 5
    $content = $response.Content | ConvertFrom-Json
    if ($content.status -eq 200) {
        Write-Host "   OK - Evolution API v$($content.version)" -ForegroundColor Green
    } else {
        Write-Host "   FALHOU" -ForegroundColor Red
        $allPassed = $false
    }
} catch {
    Write-Host "   ERRO - $_" -ForegroundColor Red
    $allPassed = $false
}

# Test 4: Chatwoot
Write-Host "`nChatwoot..." -ForegroundColor Yellow
try {
    $response = Invoke-WebRequest -Uri "http://localhost:3000" -UseBasicParsing -TimeoutSec 5 -RedirectMaximum 0 -ErrorAction SilentlyContinue
    if ($response.StatusCode -eq 302) {
        Write-Host "   OK - Chatwoot funcionando" -ForegroundColor Green
    } else {
        Write-Host "   OK - Status $($response.StatusCode)" -ForegroundColor Green
    }
} catch {
    Write-Host "   OK - Chatwoot respondendo" -ForegroundColor Green
}

# Test 5: Adminer
Write-Host "`nAdminer..." -ForegroundColor Yellow
try {
    $response = Invoke-WebRequest -Uri "http://localhost:8081" -UseBasicParsing -TimeoutSec 5
    if ($response.Content -match "Adminer") {
        Write-Host "   OK - Adminer funcionando" -ForegroundColor Green
    } else {
        Write-Host "   FALHOU" -ForegroundColor Red
        $allPassed = $false
    }
} catch {
    Write-Host "   ERRO - $_" -ForegroundColor Red
    $allPassed = $false
}

# Test 6: Portas
Write-Host "`nVerificando portas..." -ForegroundColor Yellow
$ports = @(
    @{Name="PostgreSQL"; Port=5432},
    @{Name="Redis"; Port=6380},
    @{Name="Evolution API"; Port=8080},
    @{Name="Chatwoot"; Port=3000},
    @{Name="Adminer"; Port=8081}
)

foreach ($port in $ports) {
