            Write-Host "   AVISO - $($port.Name) porta $($port.Port) nao detectada" -ForegroundColor Yellow
        }
    } catch {
        Write-Host "   AVISO - Nao foi possivel verificar $($port.Name)" -ForegroundColor Yellow
    }
}

# Resumo Final
Write-Host "`n====================================" -ForegroundColor Cyan
if ($allPassed) {
    Write-Host "   TODOS OS TESTES PASSARAM!" -ForegroundColor Green
    Write-Host "====================================`n" -ForegroundColor Cyan
    Write-Host "Consulte CREDENCIAIS.md para acessar os servicos." -ForegroundColor White
    Write-Host "Para iniciar o N8N: .\start-n8n.ps1`n" -ForegroundColor White
    exit 0
} else {
    Write-Host "   ALGUNS TESTES FALHARAM" -ForegroundColor Yellow
    Write-Host "====================================`n" -ForegroundColor Cyan
    Write-Host "Verifique os logs com: docker compose logs <servico>`n" -ForegroundColor White
    exit 1
}

