# ============================================================================
# TUNNEL SERVEO - EVOLUTION API (localhost:8080)
# Subdomain: maceio-evo-v1.serveousercontent.com
# ============================================================================
# MELHORIA: SSH Control Socket para desligamento limpo
# ============================================================================

param(
    [switch]$NoReconnect
)

# Configuration
$SUBDOMAIN = "maceio-evo-v1"
$LOCAL_PORT = "8080"
$SERVEO_HOST = "serveo.net"
$SERVICE_NAME = "Evolution API"
$SOCKET_PATH = "$env:USERPROFILE\.ssh\tunnel-evolution.sock"

# Output function
function Write-ColorOutput {
    param(
        [string]$Message,
        [string]$Color = "White"
    )
    Write-Host "[$(Get-Date -Format 'HH:mm:ss')] $Message" -ForegroundColor $Color
}

# ============================================================================
# FUNCTION: Kill tunnel via SSH control socket (clean shutdown)
# ============================================================================
function Stop-TunnelViaSocket {
    Write-ColorOutput "[SOCKET] Attempting clean shutdown via control socket..." "Cyan"

    try {
        # Check if socket exists and is active
        $checkResult = & ssh -S "$SOCKET_PATH" -O check "$SERVEO_HOST" 2>&1

        if ($LASTEXITCODE -eq 0) {
            # Socket is active - exit cleanly
            $null = & ssh -S "$SOCKET_PATH" -O exit "$SERVEO_HOST" 2>&1
            Write-ColorOutput "[SOCKET] Clean shutdown initiated" "Green"
            Start-Sleep -Milliseconds 500
            return $true
        } else {
            Write-ColorOutput "[SOCKET] No active control socket found" "Yellow"
            return $false
        }
    } catch {
        Write-ColorOutput "[SOCKET] Control socket command failed: $_" "Yellow"
        return $false
    }
}

# ============================================================================
# FUNCTION: Remove old socket file if exists
# ============================================================================
function Remove-OldSocket {
    if (Test-Path "$SOCKET_PATH") {
        Write-ColorOutput "[CLEAN] Removing old socket file: $SOCKET_PATH" "Yellow"
        try {
            Remove-Item "$SOCKET_PATH" -Force -ErrorAction Stop
            Write-ColorOutput "[OK] Old socket removed" "Green"
        } catch {
            Write-ColorOutput "[WARN] Could not remove socket: $_" "Yellow"
        }
    }
}

# ============================================================================
# FUNCTION: Remove ALL Serveo tunnels (aggressive cleanup)
# ============================================================================
function Remove-OrphanTunnels {
    Write-ColorOutput "[CLEAN] Looking for ALL Serveo SSH processes..." "Cyan"

    try {
        # Find ALL SSH processes connecting to serveo.net
        $sshProcesses = Get-CimInstance Win32_Process | Where-Object {
            $_.Name -eq 'ssh.exe' -and
            $_.CommandLine -match 'serveo\.net'
        } | Sort-Object ProcessId -Descending

        if ($sshProcesses.Count -eq 0) {
            Write-ColorOutput "[OK] No Serveo tunnels found" "Green"
            return $true
        }

        Write-ColorOutput "[CLEAN] Found $($sshProcesses.Count) Serveo tunnel(s) - REMOVING ALL!" "Yellow"

        # KILL ALL Serveo processes
        foreach ($proc in $sshProcesses) {
            try {
                Stop-Process -Id $proc.ProcessId -Force -ErrorAction SilentlyContinue
                Write-ColorOutput "  [KILLED] PID $($proc.ProcessId)" "Red"
                Start-Sleep -Milliseconds 100
            } catch {
                Write-ColorOutput "  [ERROR] Failed to kill PID $($proc.ProcessId): $_" "Red"
            }
        }

        Write-ColorOutput "[OK] All Serveo tunnels removed" "Green"
        Start-Sleep -Seconds 1
        return $true
    } catch {
        Write-ColorOutput "[ERROR] Error removing tunnels: $_" "Red"
        return $false
    }
}

# ============================================================================
# FUNCTION: Test if local service is responding
# ============================================================================
function Test-LocalService {
    try {
        $response = Invoke-WebRequest -Uri "http://localhost:$LOCAL_PORT" -Method Head -TimeoutSec 3 -ErrorAction SilentlyContinue
        return $response.StatusCode -eq 200
    } catch {
        return $false
    }
}

# ============================================================================
# FUNCTION: Test if public URL is responding
# ============================================================================
function Test-PublicURL {
    param(
        [string]$Url,
        [int]$Timeout = 10
    )

    try {
        $response = Invoke-WebRequest -Uri $Url -Method Head -TimeoutSec $Timeout -ErrorAction SilentlyContinue
        return $true
    } catch {
        return $false
    }
}

# ============================================================================
# FUNCTION: Start SSH tunnel with CONTROL SOCKET
# ============================================================================
function Start-ServeoTunnel {
    Write-ColorOutput "[START] Starting Serveo tunnel for $SERVICE_NAME..." "Cyan"
    Write-ColorOutput "   Subdomain: $SUBDOMAIN.$SERVEO_HOST" "Cyan"
    Write-ColorOutput "   Local: localhost:$LOCAL_PORT" "Cyan"
    Write-ColorOutput "   Control Socket: $SOCKET_PATH" "Cyan"
    Write-ColorOutput ""

    # Ensure .ssh directory exists
    $sshDir = Split-Path "$SOCKET_PATH" -Parent
    if (-not (Test-Path "$sshDir")) {
        New-Item -ItemType Directory -Path "$sshDir" -Force | Out-Null
    }

    # Remove old socket if exists
    Remove-OldSocket

    # SSH options:
    # -M: Master mode (allows control socket)
    # -S <path>: Control socket path
    # -f: Daemonize (run in background)
    # -N: No remote command (just tunneling)
    # -R: Remote port forwarding
    # - ServerAliveInterval=60: Send keep-alive every 60 seconds
    # - ServerAliveCountMax=3: After 3 failures, terminate connection
    # - ExitOnForwardFailure=yes: Terminate if tunnel creation fails
    # - StrictHostKeyChecking=no: Don't ask for host key confirmation
    $sshArgs = @(
        "-M", "-S", "$SOCKET_PATH",
        "-f", "-N",
        "-R", "${SUBDOMAIN}:80:localhost:${LOCAL_PORT}",
        "-o", "ServerAliveInterval=60",
        "-o", "ServerAliveCountMax=3",
        "-o", "ExitOnForwardFailure=yes",
        "-o", "StrictHostKeyChecking=no",
        "-o", "UserKnownHostsFile=nul",
        $SERVEO_HOST
    )

    Write-ColorOutput "[CONNECT] Connecting to Serveo with control socket..." "Yellow"

    try {
        # Start SSH process with control socket
        $process = Start-Process -FilePath "ssh" -ArgumentList $sshArgs -PassThru -NoNewWindow

        # Wait for connection to establish
        Write-ColorOutput "[WAIT] Waiting for tunnel to be ready..." "Yellow"
        Start-Sleep -Seconds 10

        # Check if process is still running
        $stillRunning = Get-Process -Id $process.Id -ErrorAction SilentlyContinue

        if (-not $stillRunning) {
            Write-ColorOutput "[ERROR] SSH process terminated unexpectedly" "Red"
            Remove-OldSocket
            return $null
        }

        # Verify control socket is working
        Write-ColorOutput "[SOCKET] Verifying control socket..." "Yellow"
        $socketCheck = & ssh -S "$SOCKET_PATH" -O check "$SERVEO_HOST" 2>&1

        if ($LASTEXITCODE -ne 0) {
            Write-ColorOutput "[WARN] Control socket not responding (this is OK on some systems)" "Yellow"
        } else {
            Write-ColorOutput "[OK] Control socket active" "Green"
        }

        # Verify tunnel is actually working by testing the public URL
        Write-ColorOutput "[VERIFY] Testing if tunnel is working..." "Yellow"
        $publicUrl = "https://${SUBDOMAIN}.serveousercontent.com"
        $working = $false

        # Try up to 3 times to verify
        for ($i = 1; $i -le 3; $i++) {
            Write-ColorOutput "[VERIFY] Attempt $i of 3..." "Cyan"

            if (Test-PublicURL -Url $publicUrl -Timeout 5) {
                $working = $true
                break
            }

            if ($i -lt 3) {
                Write-ColorOutput "[VERIFY] Not working yet, waiting 3 more seconds..." "Yellow"
                Start-Sleep -Seconds 3
            }
        }

        if ($working) {
            Write-ColorOutput "" "White"
            Write-ColorOutput "============================================================" "Green"
            Write-ColorOutput "=  TUNNEL ACTIVE AND WORKING!                             =" "Green"
            Write-ColorOutput "============================================================" "Green"
            Write-ColorOutput "=  URL: https://$SUBDOMAIN.serveousercontent.com         =" "White"
            Write-ColorOutput "=  PID: $($process.Id)                                      =" "White"
            Write-ColorOutput "=  STATUS: VERIFIED (URL tested)                          =" "Green"
            Write-ColorOutput "=  SOCKET: Control socket enabled                         =" "Green"
            Write-ColorOutput "=                                                         =" "White"
            Write-ColorOutput "=  Press Ctrl+C to stop this tunnel                       =" "Yellow"
            Write-ColorOutput "=  (Clean shutdown via control socket)                    =" "Yellow"
            Write-ColorOutput "============================================================" "Green"
            Write-ColorOutput "" "White"

            return $process
        } else {
            Write-ColorOutput "[ERROR] Tunnel created but URL not responding!" "Red"
            Write-ColorOutput "[ERROR] Orphan tunnel exists on Serveo - trying aggressive cleanup..." "Red"

            # Clean shutdown via socket
            Stop-TunnelViaSocket

            # Kill the process
            try {
                Stop-Process -Id $process.Id -Force -ErrorAction SilentlyContinue
            } catch {}

            Remove-OldSocket
            return $null
        }
    } catch {
        Write-ColorOutput "[ERROR] Error starting tunnel: $_" "Red"
        Remove-OldSocket
        return $null
    }
}

# ============================================================================
# CLEANUP FUNCTION: Called on script exit (Ctrl+C, etc.)
# ============================================================================
function Cleanup-OnExit {
    Write-ColorOutput "" "White"
    Write-ColorOutput "[CLEANUP] Cleaning up tunnel..." "Yellow"

    # Try clean shutdown via socket first
    Stop-TunnelViaSocket

    # Remove socket file
    Remove-OldSocket

    Write-ColorOutput "[CLEANUP] Cleanup complete" "Green"
}

# ============================================================================
# MAIN SCRIPT
# ============================================================================

# Set up cleanup handler for Ctrl+C
$null = Register-EngineEvent -SourceIdentifier PowerShell.Exiting -Action {
    Cleanup-OnExit
}

# Trap Ctrl+C
trap {
    Cleanup-OnExit
    exit 0
}

Clear-Host

# No delay - start immediately
Write-ColorOutput "[STARTUP] Connecting immediately..." "Cyan"
Write-ColorOutput ""
Write-ColorOutput "============================================================" "Cyan"
Write-ColorOutput "=     TUNNEL SERVEO - EVOLUTION API                        =" "Cyan"
Write-ColorOutput "=     localhost:8080 -> maceio-evo-v1.serveousercontent.com =" "Cyan"
Write-ColorOutput "=     WITH SSH CONTROL SOCKET                             =" "Cyan"
Write-ColorOutput "============================================================" "Cyan"
Write-ColorOutput "" "White"

# Check if local service is running
Write-ColorOutput "[CHECK] Verifying if $SERVICE_NAME is running on port $LOCAL_PORT..." "Yellow"
if (-not (Test-LocalService)) {
    Write-ColorOutput "[WARN] $SERVICE_NAME doesn't seem to be responding!" "Yellow"
    Write-ColorOutput "   Check if Docker is running: docker compose ps" "Yellow"
    Write-ColorOutput "" "White"
    $response = Read-Host "Continue anyway? (s/N)"
    if ($response -ne "s" -and $response -ne "S") {
        Write-ColorOutput "[ABORT] Operation cancelled" "Red"
        exit 1
    }
}

# Clean orphan tunnels before starting
$cleanResult = Remove-OrphanTunnels
if (-not $cleanResult) {
    Write-ColorOutput "[WARN] Continuing anyway..." "Yellow"
}

Write-ColorOutput "" "White"

# Main auto-reconnect loop
do {
    $tunnelProcess = Start-ServeoTunnel

    if ($null -eq $tunnelProcess) {
        Write-ColorOutput "[RETRY] Server blocking subdomain - reconnecting aggressively..." "Yellow"
        # NO delay - retry immediately to force Serveo release
        continue
    }

    # Wait for process to finish (or Ctrl+C)
    try {
        $tunnelProcess.WaitForExit()
    } catch [System.Management.Automation.PipelineStoppedException] {
        # Ctrl+C pressed - trap will handle cleanup
        Write-ColorOutput "" "White"
        Write-ColorOutput "[STOP] Interrupt detected!" "Yellow"
        Cleanup-OnExit
        break
    }

    # If we got here, process terminated unexpectedly
    Write-ColorOutput "" "White"
    Write-ColorOutput "[WARN] Connection terminated unexpectedly!" "Yellow"
    Write-ColorOutput "   Reconnecting immediately..." "Yellow"
    Write-ColorOutput "" "White"

    # Cleanup before reconnecting
    Cleanup-OnExit

    # NO DELAY - reconnect immediately
    # Check orphan tunnels again before reconnecting
    Remove-OrphanTunnels

} while (-not $NoReconnect)

Write-ColorOutput "" "White"
Write-ColorOutput "[DONE] Script finished" "Cyan"

# ============================================================================
# TUNNEL SERVEO - CHATWOOT (localhost:3000)
# Subdomain: maceio-chat-v1.serveousercontent.com
# ============================================================================
# MELHORIA: SSH Control Socket para desligamento limpo
# ============================================================================

param(
    [switch]$NoReconnect
)

# Configuration
$SUBDOMAIN = "maceio-chat-v1"
$LOCAL_PORT = "3000"
$SERVEO_HOST = "serveo.net"
$SERVICE_NAME = "Chatwoot"
$SOCKET_PATH = "$env:USERPROFILE\.ssh\tunnel-chatwoot.sock"

# Output function
function Write-ColorOutput {
    param(
        [string]$Message,
        [string]$Color = "White"
    )
    Write-Host "[$(Get-Date -Format 'HH:mm:ss')] $Message" -ForegroundColor $Color
}

# ============================================================================
# FUNCTION: Kill tunnel via SSH control socket (clean shutdown)
# ============================================================================
function Stop-TunnelViaSocket {
    Write-ColorOutput "[SOCKET] Attempting clean shutdown via control socket..." "Cyan"

    try {
        # Check if socket exists and is active
        $checkResult = & ssh -S "$SOCKET_PATH" -O check "$SERVEO_HOST" 2>&1

        if ($LASTEXITCODE -eq 0) {
            # Socket is active - exit cleanly
            $null = & ssh -S "$SOCKET_PATH" -O exit "$SERVEO_HOST" 2>&1
            Write-ColorOutput "[SOCKET] Clean shutdown initiated" "Green"
            Start-Sleep -Milliseconds 500
            return $true
        } else {
            Write-ColorOutput "[SOCKET] No active control socket found" "Yellow"
            return $false
        }
    } catch {
        Write-ColorOutput "[SOCKET] Control socket command failed: $_" "Yellow"
        return $false
    }
}

# ============================================================================
# FUNCTION: Remove old socket file if exists
# ============================================================================
function Remove-OldSocket {
    if (Test-Path "$SOCKET_PATH") {
        Write-ColorOutput "[CLEAN] Removing old socket file: $SOCKET_PATH" "Yellow"
        try {
            Remove-Item "$SOCKET_PATH" -Force -ErrorAction Stop
            Write-ColorOutput "[OK] Old socket removed" "Green"
        } catch {
            Write-ColorOutput "[WARN] Could not remove socket: $_" "Yellow"
        }
    }
}

# ============================================================================
# FUNCTION: Remove ALL Serveo tunnels (aggressive cleanup)
# ============================================================================
function Remove-OrphanTunnels {
    Write-ColorOutput "[CLEAN] Looking for ALL Serveo SSH processes..." "Cyan"

    try {
        # Find ALL SSH processes connecting to serveo.net
        $sshProcesses = Get-CimInstance Win32_Process | Where-Object {
            $_.Name -eq 'ssh.exe' -and
            $_.CommandLine -match 'serveo\.net'
        } | Sort-Object ProcessId -Descending

        if ($sshProcesses.Count -eq 0) {
            Write-ColorOutput "[OK] No Serveo tunnels found" "Green"
            return $true
        }

        Write-ColorOutput "[CLEAN] Found $($sshProcesses.Count) Serveo tunnel(s) - REMOVING ALL!" "Yellow"

        # KILL ALL Serveo processes
        foreach ($proc in $sshProcesses) {
            try {
                Stop-Process -Id $proc.ProcessId -Force -ErrorAction SilentlyContinue
                Write-ColorOutput "  [KILLED] PID $($proc.ProcessId)" "Red"
                Start-Sleep -Milliseconds 100
            } catch {
                Write-ColorOutput "  [ERROR] Failed to kill PID $($proc.ProcessId): $_" "Red"
            }
        }

        Write-ColorOutput "[OK] All Serveo tunnels removed" "Green"
        Start-Sleep -Seconds 1
        return $true
    } catch {
        Write-ColorOutput "[ERROR] Error removing tunnels: $_" "Red"
        return $false
    }
}

