# =============================================================================
# VERIFICAÇÃO RÁPIDA - Docker Stack Status
# =============================================================================
# Uso: .\verificar-rapido.ps1
# Verifica o status dos principais serviços rapidamente
# =============================================================================

Clear-Host

Write-Host "`n╔════════════════════════════════════════════════════════════╗" -ForegroundColor Cyan
Write-Host "║          VERIFICAÇÃO RÁPIDA - Docker Stack                 ║" -ForegroundColor Cyan
Write-Host "╚════════════════════════════════════════════════════════════╝`n" -ForegroundColor Cyan

# Cores
$ok = [ConsoleColor]::Green
$warn = [ConsoleColor]::Yellow
$err = [ConsoleColor]::Red
$info = [ConsoleColor]::Cyan

# 1. Verificar Docker
Write-Host "[-] Docker: " -NoNewline -ForegroundColor $info
try {
    $null = Get-Process docker -ErrorAction Stop
    Write-Host "RUNNING" -ForegroundColor $ok
} catch {
    Write-Host "NOT RUNNING" -ForegroundColor $err
    exit 1
}

# 2. Verificar Containers
Write-Host "`n[─] Containers Docker:" -ForegroundColor $info
$containers = docker compose ps -q 2>$null
if ($containers) {
    $count = (docker compose ps -q | Measure-Object).Count
    Write-Host "    [$count containers ativos]" -ForegroundColor $ok
} else {
    Write-Host "    [NENHUM CONTAINER ATIVO]" -ForegroundColor $err
    Write-Host "    Execute: docker compose up -d" -ForegroundColor $warn
}

# 3. Testar Serviços
Write-Host "`n[─] Teste de Conectividade:" -ForegroundColor $info

$services = @(
    @{Name="Nginx Proxy"; Port=8081; Path="/health"},
    @{Name="Evolution API"; Port=8080; Path="/"},
    @{Name="Chatwoot"; Port=3000; Path="/"},
    @{Name="N8N"; Port=5678; Path="/"}
)

foreach ($svc in $services) {
    Write-Host "    [$($svc.Name)] " -NoNewline
    try {
        $response = Invoke-WebRequest -Uri "http://localhost:$($svc.Port)$($svc.Path)" -UseBasicParsing -TimeoutSec 2 -ErrorAction Stop
        if ($response.StatusCode -eq 200) {
            Write-Host "✓ OK" -ForegroundColor $ok
        } else {
            Write-Host "? Status $($response.StatusCode)" -ForegroundColor $warn
        }
    } catch {
        Write-Host "✗ FALHOU" -ForegroundColor $err
    }
}

# 4. Portas em uso
Write-Host "`n[─] Portas:" -ForegroundColor $info
$ports = @(8081, 8080, 3000, 5678, 5432, 6380, 8082)
foreach ($port in $ports) {
    $listener = [System.Net.NetworkInformation.IPGlobalProperties]::GetIPGlobalProperties().GetActiveTcpListeners() | Where-Object { $_.Port -eq $port }
