toolUseResult.content:
# =============================================================================
# QUICK CHECK - Docker Stack Status
# =============================================================================

Clear-Host

Write-Host ""
Write-Host "============================================================"
Write-Host "  QUICK CHECK - Docker Stack"
Write-Host "============================================================"
Write-Host ""

# 1. Check Docker
Write-Host "[-] Docker: " -NoNewline
try {
    $dockerProcess = Get-Process docker -ErrorAction Stop
    Write-Host "RUNNING" -ForegroundColor Green
} catch {
    Write-Host "NOT RUNNING" -ForegroundColor Red
    exit 1
}

# 2. Check Containers
Write-Host ""
Write-Host "[~] Containers:" -ForegroundColor Cyan
$containers = docker compose ps -q 2>$null
if ($containers) {
    $count = (docker compose ps -q | Measure-Object).Count
    Write-Host "    [$count containers running]" -ForegroundColor Green
} else {
    Write-Host "    [NO CONTAINER ACTIVE]" -ForegroundColor Red
    Write-Host "    Run: docker compose up -d" -ForegroundColor Yellow
}

# 3. Test Services
Write-Host ""
Write-Host "[~] Services:" -ForegroundColor Cyan

# Test Nginx
Write-Host "    [Nginx] " -NoNewline
try {
    $response = Invoke-WebRequest -Uri "http://localhost:8081/health" -UseBasicParsing -TimeoutSec 2
    Write-Host "OK" -ForegroundColor Green
} catch {
    Write-Host "FAILED" -ForegroundColor Red
}

# Test Evolution
Write-Host "    [Evolution] " -NoNewline
try {
    $response = Invoke-WebRequest -Uri "http://localhost:8080" -UseBasicParsing -TimeoutSec 2
    Write-Host "OK" -ForegroundColor Green
} catch {
    Write-Host "FAILED" -ForegroundColor Red
}

# Test Chatwoot
Write-Host "    [Chatwoot] " -NoNewline
try {
    $response = Invoke-WebRequest -Uri "http://localhost:3000" -UseBasicParsing -TimeoutSec 2
    Write-Host "OK" -ForegroundColor Green
} catch {
    Write-Host "FAILED" -ForegroundColor Red
}

# Test N8N
Write-Host "    [N8N] " -NoNewline
try {
    $response = Invoke-WebRequest -Uri "http://localhost:5678" -UseBasicParsing -TimeoutSec 2
    Write-Host "OK" -ForegroundColor Green
} catch {
    Write-Host "FAILED" -ForegroundColor Red
}

# 4. Check Ports
Write-Host ""
Write-Host "[~] Ports:" -ForegroundColor Cyan
$ports = @(8081, 8080, 3000, 5678, 5432, 6380, 8082)
foreach ($port in $ports) {
    $listener = [System.Net.NetworkInformation.IPGlobalProperties]::GetIPGlobalProperties().GetActiveTcpListeners() | Where-Object { $_.Port -eq $port }
    if ($listener) {
        Write-Host "    [$port] OK" -ForegroundColor Green
    } else {
        Write-Host "    [$port] FREE" -ForegroundColor Yellow
    }
}

# 5. Check Tunnel
Write-Host ""
Write-Host "[~] Tunnel:" -ForegroundColor Cyan
try {
    $sshProcesses = Get-CimInstance Win32_Process -Filter "Name = 'ssh.exe'" 2>$null
    $ssh = $sshProcesses | Where-Object { $_.CommandLine -match 'maceio-all-serveo' }

    if ($ssh) {
        Write-Host "    [ACTIVE] PID $($ssh.ProcessId)" -ForegroundColor Green
        Write-Host "    Public URLs:" -ForegroundColor Cyan
        Write-Host "    - N8N:       https://maceio-all-serveo.serveousercontent.com/n8n/"
        Write-Host "    - Evolution: https://maceio-all-serveo.serveousercontent.com/evo/"
        Write-Host "    - Chatwoot:  https://maceio-all-serveo.serveousercontent.com/chat/"
    } else {
        Write-Host "    [INACTIVE] Run: .tunnel-all.ps1" -ForegroundColor Yellow
    }
} catch {
    Write-Host "    [ERROR]" -ForegroundColor Red
}

# Summary
Write-Host ""
Write-Host "============================================================"
Write-Host "  Next Steps:"
Write-Host "============================================================"
